// generated by sprint 61-1 — macOS .dmg build orchestration

import {
  type MacOSBuildConfig,
  type BuildResult,
  type BuildArtifact,
  type BuildEnvironment,
  APP_NAME,
} from "./types";
import { buildCodesignCommand, buildCodesignVerifyCommand } from "./codesign";
import { buildFullNotarizationPipeline } from "./notarize";

export interface DmgBuildStage {
  readonly name: string;
  readonly commands: string[][];
  readonly required: boolean;
  readonly description: string;
}

export function buildTauriBuildCommand(
  release: boolean = true,
  target?: string
): string[] {
  const args = ["npx", "tauri", "build"];

  if (!release) {
    args.push("--debug");
  }

  if (target) {
    args.push("--target", target);
  }

  args.push("--bundles", "dmg,app");

  return args;
}

export function buildUniversalBinaryCommands(
  appName: string,
  buildDir: string
): string[][] {
  const x86Path = `${buildDir}/x86_64-apple-darwin/release/bundle/macos/${appName}.app`;
  const armPath = `${buildDir}/aarch64-apple-darwin/release/bundle/macos/${appName}.app`;
  const universalPath = `${buildDir}/universal-apple-darwin/release/bundle/macos/${appName}.app`;
  const universalBinary = `${universalPath}/Contents/MacOS/${appName.toLowerCase().replace(/\s+/g, "-")}`;
  const x86Binary = `${x86Path}/Contents/MacOS/${appName.toLowerCase().replace(/\s+/g, "-")}`;
  const armBinary = `${armPath}/Contents/MacOS/${appName.toLowerCase().replace(/\s+/g, "-")}`;

  return [
    ["mkdir", "-p", `${universalPath}/Contents/MacOS`],
    ["cp", "-R", `${armPath}/Contents/Resources`, `${universalPath}/Contents/`],
    ["cp", `${armPath}/Contents/Info.plist`, `${universalPath}/Contents/`],
    [
      "lipo",
      "-create",
      "-output",
      universalBinary,
      x86Binary,
      armBinary,
    ],
  ];
}

export function generateDmgBuildStages(
  config: MacOSBuildConfig
): DmgBuildStage[] {
  const stages: DmgBuildStage[] = [];

  stages.push({
    name: "install-dependencies",
    commands: [["npm", "ci"]],
    required: true,
    description: "Install Node.js dependencies",
  });

  stages.push({
    name: "build-frontend",
    commands: [["npm", "run", "build"]],
    required: true,
    description: "Build Svelte frontend for production",
  });

  stages.push({
    name: "build-tauri-aarch64",
    commands: [buildTauriBuildCommand(true, "aarch64-apple-darwin")],
    required: true,
    description: "Build Tauri app for Apple Silicon (aarch64)",
  });

  stages.push({
    name: "build-tauri-x86_64",
    commands: [buildTauriBuildCommand(true, "x86_64-apple-darwin")],
    required: true,
    description: "Build Tauri app for Intel (x86_64)",
  });

  stages.push({
    name: "create-universal-binary",
    commands: buildUniversalBinaryCommands(
      config.appName,
      "src-tauri/target"
    ),
    required: true,
    description: "Create universal binary from both architectures",
  });

  if (config.signingIdentity) {
    const appPath = `src-tauri/target/universal-apple-darwin/release/bundle/macos/${config.appName}.app`;

    stages.push({
      name: "codesign",
      commands: [
        buildCodesignCommand(
          appPath,
          config.signingIdentity,
          config.entitlements
        ),
        buildCodesignVerifyCommand(appPath),
      ],
      required: true,
      description: "Sign the application bundle with Developer ID",
    });
  }

  stages.push({
    name: "create-dmg",
    commands: [buildCreateDmgCommand(config)],
    required: true,
    description: "Package signed app into .dmg installer",
  });

  if (config.signingIdentity && config.notarization) {
    const dmgPath = resolveDmgOutputPath(config);
    const pipeline = buildFullNotarizationPipeline(
      dmgPath,
      config.notarization
    );

    stages.push({
      name: "notarize",
      commands: pipeline.map((p) => p.command),
      required: true,
      description: "Submit .dmg for Apple notarization and staple ticket",
    });
  }

  stages.push({
    name: "verify-artifact",
    commands: [
      buildVerifyDmgCommand(resolveDmgOutputPath(config)),
    ],
    required: true,
    description: "Verify final .dmg artifact integrity",
  });

  return stages;
}

function buildCreateDmgCommand(config: MacOSBuildConfig): string[] {
  const dmgPath = resolveDmgOutputPath(config);
  const appPath = `src-tauri/target/universal-apple-darwin/release/bundle/macos/${config.appName}.app`;

  const args = [
    "create-dmg",
    "--volname",
    config.dmg.title,
    "--window-size",
    String(config.dmg.windowWidth),
    String(config.dmg.windowHeight),
    "--icon-size",
    String(config.dmg.iconSize),
  ];

  if (config.dmg.background) {
    args.push("--background", config.dmg.background);
  }

  for (const content of config.dmg.contents) {
    if (content.type === "link") {
      args.push(
        "--icon",
        content.name,
        String(content.x),
        String(content.y)
      );
    } else {
      args.push(
        "--icon",
        content.name,
        String(content.x),
        String(content.y)
      );
    }
  }

  args.push("--app-drop-link", "480", "170");
  args.push(dmgPath, appPath);

  return args;
}

function buildVerifyDmgCommand(dmgPath: string): string[] {
  return ["hdiutil", "verify", dmgPath];
}

export function resolveDmgOutputPath(config: MacOSBuildConfig): string {
  const sanitizedName = config.appName
    .toLowerCase()
    .replace(/\s+/g, "-");
  return `dist/${sanitizedName}-${config.version}-macos-universal.dmg`;
}

export function resolveDmgFilename(config: MacOSBuildConfig): string {
  const sanitizedName = config.appName
    .toLowerCase()
    .replace(/\s+/g, "-");
  return `${sanitizedName}-${config.version}-macos-universal.dmg`;
}

export function buildArtifactMetadata(
  config: MacOSBuildConfig,
  dmgPath: string,
  sha256: string,
  fileSize: number
): BuildArtifact {
  return {
    path: dmgPath,
    filename: resolveDmgFilename(config),
    size: fileSize,
    sha256,
    createdAt: new Date().toISOString(),
  };
}

export function generateBuildSummary(
  config: MacOSBuildConfig,
  stages: DmgBuildStage[],
  artifacts: BuildArtifact[],
  errors: string[],
  durationMs: number
): BuildResult {
  return {
    success: errors.length === 0,
    artifacts,
    errors,
    warnings: config.signingIdentity
      ? []
      : ["Build is unsigned — not suitable for distribution"],
    duration: durationMs,
  };
}
